import { fireEvent, render, screen } from '@testing-library/react';
import { describe, expect, it } from 'vitest';
import Summary from '../../../../../src/webview/components/timeline/view/Summary';

const mergeCommit = {
  author: 'Grace Hopper',
  message: 'Stabilize timeline panel\nAdds the current commit summary and details.',
  parents: ['aaa111', 'bbb222'],
  sha: 'ccc333ccc333ccc333ccc333ccc333ccc333ccc3',
  timestamp: 1709294400,
};

describe('timeline/Summary', () => {
  it('renders current commit metadata and message details', () => {
    render(
      <Summary
        collapsed={false}
        currentCommit={mergeCommit}
        currentIndex={2}
        onToggle={() => {}}
        totalCommits={8}
      />,
    );

    expect(screen.getByText('Current Commit')).toBeInTheDocument();
    expect(screen.getByText('ccc333c')).toBeInTheDocument();
    expect(screen.getByText('Stabilize timeline panel')).toBeInTheDocument();
    expect(screen.getByText('Adds the current commit summary and details.')).toBeInTheDocument();
    expect(screen.getByText('Grace Hopper')).toBeInTheDocument();
    expect(screen.getByText('3 of 8')).toBeInTheDocument();
    expect(screen.getByText('Merge commit')).toBeInTheDocument();
    expect(screen.getByRole('button', { name: 'Current Commit' })).toHaveAttribute('aria-expanded', 'true');
    expect(screen.getByTestId('settings-panel-chevron')).toHaveClass('rotate-90');
  });

  it('renders a root-commit badge and omits the body for a simple one-line root commit', () => {
    render(
      <Summary
        collapsed={false}
        currentCommit={{
          author: 'Alice',
          message: 'Initial import',
          parents: [],
          sha: 'aaa111aaa111aaa111aaa111aaa111aaa111aaa1',
          timestamp: 1709208000,
        }}
        currentIndex={0}
        onToggle={() => {}}
        totalCommits={1}
      />,
    );

    expect(screen.queryByText('Merge commit')).not.toBeInTheDocument();
    expect(screen.getByText('Root commit')).toBeInTheDocument();
    expect(screen.queryByTestId('timeline-summary-body')).not.toBeInTheDocument();
  });

  it('collapses the current commit details behind a toggle', () => {
    const onToggle = vi.fn();

    render(
      <Summary
        collapsed={true}
        currentCommit={mergeCommit}
        currentIndex={2}
        onToggle={onToggle}
        totalCommits={8}
      />,
    );

    expect(screen.getByRole('button', { name: 'Current Commit' })).toHaveAttribute('aria-expanded', 'false');
    expect(screen.getByTestId('settings-panel-chevron')).not.toHaveClass('rotate-90');
    expect(screen.getByText('3 of 8')).toBeInTheDocument();
    expect(screen.queryByText('Merge commit')).not.toBeInTheDocument();
    expect(screen.queryByText('Stabilize timeline panel')).not.toBeInTheDocument();

    fireEvent.click(screen.getByRole('button', { name: 'Current Commit' }));

    expect(onToggle).toHaveBeenCalledTimes(1);
  });
});

import { fireEvent, render, screen } from '@testing-library/react';
import { describe, expect, it, vi } from 'vitest';
import Controls from '../../../../../src/webview/components/timeline/view/Controls';

describe('timeline/Controls', () => {
  it('renders icon transport controls, a muted date readout, and boundary disabled states', () => {
    render(
      <Controls
        currentDateLabel="Jan 4, 2024"
        isAtEnd={false}
        isAtStart={true}
        isPlaying={false}
        onJumpToEnd={vi.fn()}
        onJumpToNext={vi.fn()}
        onJumpToPrevious={vi.fn()}
        onJumpToStart={vi.fn()}
        onPlayPause={vi.fn()}
      />,
    );

    expect(screen.getByText('Jan 4, 2024')).toBeInTheDocument();
    expect(screen.queryByText('Viewing Date')).not.toBeInTheDocument();
    expect(screen.getByRole('button', { name: 'Start' })).toBeDisabled();
    expect(screen.getByRole('button', { name: 'Prev' })).toBeDisabled();
    expect(screen.getByRole('button', { name: 'Play' })).toBeEnabled();
    expect(screen.getByRole('button', { name: 'Play' })).toHaveAttribute('aria-label', 'Play');
    expect(screen.getByRole('button', { name: 'Play' })).toHaveAttribute('title', 'Play');
    expect(screen.getByRole('button', { name: 'Next' })).toBeEnabled();
    expect(screen.getByRole('button', { name: 'End' })).toBeEnabled();
  });

  it('delegates click handlers for the navigation controls', () => {
    const onJumpToStart = vi.fn();
    const onJumpToPrevious = vi.fn();
    const onPlayPause = vi.fn();
    const onJumpToNext = vi.fn();
    const onJumpToEnd = vi.fn();

    render(
      <Controls
        currentDateLabel="Jan 4, 2024"
        isAtEnd={false}
        isAtStart={false}
        isPlaying={true}
        onJumpToEnd={onJumpToEnd}
        onJumpToNext={onJumpToNext}
        onJumpToPrevious={onJumpToPrevious}
        onJumpToStart={onJumpToStart}
        onPlayPause={onPlayPause}
      />,
    );

    fireEvent.click(screen.getByRole('button', { name: 'Start' }));
    fireEvent.click(screen.getByRole('button', { name: 'Prev' }));
    fireEvent.click(screen.getByRole('button', { name: 'Pause' }));
    fireEvent.click(screen.getByRole('button', { name: 'Next' }));
    fireEvent.click(screen.getByRole('button', { name: 'End' }));

    expect(onJumpToStart).toHaveBeenCalledTimes(1);
    expect(onJumpToPrevious).toHaveBeenCalledTimes(1);
    expect(onPlayPause).toHaveBeenCalledTimes(1);
    expect(onJumpToNext).toHaveBeenCalledTimes(1);
    expect(onJumpToEnd).toHaveBeenCalledTimes(1);
  });

  it('switches to pause state and disables forward navigation at the end', () => {
    render(
      <Controls
        currentDateLabel="Jan 5, 2024"
        isAtEnd={true}
        isAtStart={false}
        isPlaying={true}
        onJumpToEnd={vi.fn()}
        onJumpToNext={vi.fn()}
        onJumpToPrevious={vi.fn()}
        onJumpToStart={vi.fn()}
        onPlayPause={vi.fn()}
      />,
    );

    expect(screen.getByRole('button', { name: 'Pause' })).toBeEnabled();
    expect(screen.getByRole('button', { name: 'Pause' })).toHaveAttribute('aria-label', 'Pause');
    expect(screen.getByRole('button', { name: 'Next' })).toBeDisabled();
    expect(screen.getByRole('button', { name: 'End' })).toBeDisabled();
    expect(screen.getByRole('button', { name: 'Pause' })).toHaveAttribute('title', 'Pause');
  });
});

import { fireEvent, render, screen, within } from '@testing-library/react';
import { describe, expect, it, vi } from 'vitest';
import CommitList from '../../../../../src/webview/components/timeline/view/CommitList';

const commits = [
  {
    author: 'Alice',
    message: 'Initial import',
    parents: [],
    sha: 'aaa111aaa111aaa111aaa111aaa111aaa111aaa1',
    timestamp: 1709208000,
  },
  {
    author: 'Bob',
    message: 'Add timeline controls',
    parents: ['aaa111aaa111aaa111aaa111aaa111aaa111aaa1'],
    sha: 'bbb222bbb222bbb222bbb222bbb222bbb222bbb2',
    timestamp: 1709294400,
  },
  {
    author: 'Cara',
    message: 'Tighten timeline layout',
    parents: ['bbb222bbb222bbb222bbb222bbb222bbb222bbb2'],
    sha: 'ccc333ccc333ccc333ccc333ccc333ccc333ccc3',
    timestamp: 1709380800,
  },
];

const mergeCommits = [
  commits[0],
  {
    author: 'Bob',
    message: 'Merge feature branch',
    parents: [commits[0].sha, commits[1].sha],
    sha: 'mmm444mmm444mmm444mmm444mmm444mmm444mmm4',
    timestamp: 1709294400,
  },
];

describe('timeline/CommitList', () => {
  it('renders commits newest-first and highlights the current commit', () => {
    render(
      <CommitList
        collapsed={false}
        currentCommitSha={commits[1].sha}
        onSelectCommit={vi.fn()}
        onToggle={vi.fn()}
        timelineCommits={commits}
      />,
    );

    expect(screen.getByTestId('timeline-commit-list')).toHaveClass(
      'border-t',
      'border-border',
      'min-h-0',
      'flex',
      'flex-1',
      'flex-col',
      'overflow-hidden',
    );

    const buttons = within(screen.getByTestId('timeline-commit-list-scroll')).getAllByRole('button');
    expect(buttons[0]).toHaveTextContent('Tighten timeline layout');
    expect(within(buttons[0]).getByText('ccc333c', { selector: 'span.font-mono' })).toBeInTheDocument();
    expect(within(buttons[0]).queryByText(commits[2].sha, { selector: 'span.font-mono' })).not.toBeInTheDocument();
    expect(buttons[0]).toHaveClass('hover:bg-[var(--vscode-list-hoverBackground,#2a2d2e)]');
    expect(buttons[1]).toHaveAttribute('aria-current', 'true');
    expect(buttons[1]).toHaveTextContent('Add timeline controls');
    expect(buttons[1]).toHaveClass(
      'bg-[var(--vscode-list-activeSelectionBackground,#264f78)]',
      'text-[var(--vscode-list-activeSelectionForeground,#fff)]',
    );

    expect(screen.getByTestId('timeline-commit-list-scroll')).toHaveClass('overflow-y-auto');
    expect(screen.getByTestId('settings-panel-chevron')).toHaveClass('rotate-90');
  });

  it('calls onSelectCommit with the selected sha and shows merge commits', () => {
    const onSelectCommit = vi.fn();

    render(
      <CommitList
        collapsed={false}
        currentCommitSha={mergeCommits[0].sha}
        onSelectCommit={onSelectCommit}
        onToggle={vi.fn()}
        timelineCommits={mergeCommits}
      />,
    );

    const buttons = within(screen.getByTestId('timeline-commit-list-scroll')).getAllByRole('button');
    expect(within(buttons[0]).getByText('Merge', { selector: 'span.rounded' })).toBeInTheDocument();
    fireEvent.click(screen.getByRole('button', { name: /Initial import/i }));

    expect(onSelectCommit).toHaveBeenCalledWith(mergeCommits[0].sha);
  });

  it('collapses the commit list behind a section toggle', () => {
    const onToggle = vi.fn();

    render(
      <CommitList
        collapsed={true}
        currentCommitSha={commits[1].sha}
        onSelectCommit={vi.fn()}
        onToggle={onToggle}
        timelineCommits={commits}
      />,
    );

    const toggle = screen.getByRole('button', { name: 'Commits' });

    expect(toggle).toBeInTheDocument();
    expect(toggle).toHaveAttribute('aria-expanded', 'false');
    expect(screen.getByTestId('timeline-commit-list')).toHaveClass('flex-shrink-0');
    expect(screen.getByTestId('settings-panel-chevron')).not.toHaveClass('rotate-90');
    expect(screen.queryByTestId('timeline-commit-list-scroll')).not.toBeInTheDocument();

    fireEvent.click(toggle);

    expect(onToggle).toHaveBeenCalledTimes(1);
  });
});

