    expect(sendGraphControls).not.toHaveBeenCalled();
    expect(sendPluginStatuses).not.toHaveBeenCalled();
    expect(sendDecorations).not.toHaveBeenCalled();
    expect(sendMessage).not.toHaveBeenCalled();
  });

  it('rebuilds graph data and resends groups, controls, and dependents when analyzer state is available', () => {
    const graphData: IGraphData = {
      nodes: [{ id: 'src/app.ts', label: 'app.ts', color: '#ffffff' }],
      edges: [],
    };
    const notifyGraphRebuild = vi.fn();
    const state = {
      _analyzer: {
        rebuildGraph: vi.fn(() => graphData),
        registry: { notifyGraphRebuild },
      },
      _disabledPlugins: new Set<string>(),
      _rawGraphData: { nodes: [], edges: [] } satisfies IGraphData,
      _graphData: { nodes: [], edges: [] } satisfies IGraphData,
    };
    const computeMergedGroups = vi.fn();
    const sendGroupsUpdated = vi.fn();
    const updateViewContext = vi.fn();
    const applyViewTransform = vi.fn();
    const sendDepthState = vi.fn();
    const sendGraphControls = vi.fn();
    const sendPluginStatuses = vi.fn();
    const sendDecorations = vi.fn();
    const sendMessage = vi.fn();

    rebuildGraphViewData(state, {
      getShowOrphans: () => false,
      computeMergedGroups,
      sendGroupsUpdated,
      updateViewContext,
      applyViewTransform,
      sendDepthState,
      sendGraphControls,
      sendPluginStatuses,
      sendDecorations,
      sendMessage,
    });

    expect(state._analyzer.rebuildGraph).toHaveBeenCalledWith(new Set(), false);
    expect(state._rawGraphData).toEqual(graphData);
    expect(computeMergedGroups).toHaveBeenCalledTimes(1);
    expect(sendGroupsUpdated).toHaveBeenCalledTimes(1);
    expect(updateViewContext).toHaveBeenCalledTimes(1);
    expect(applyViewTransform).toHaveBeenCalledTimes(1);
    expect(sendDepthState).toHaveBeenCalledTimes(1);
    expect(sendGraphControls).toHaveBeenCalledTimes(1);
    expect(sendPluginStatuses).toHaveBeenCalledTimes(1);
    expect(sendDecorations).toHaveBeenCalledTimes(1);
    expect(sendMessage).toHaveBeenCalledWith({
      type: 'GRAPH_DATA_UPDATED',
      payload: { nodes: [], edges: [] },
    });
    expect(notifyGraphRebuild).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('always rebuilds cached graph data for plugin toggles so legends and controls stay in sync', () => {
    const state = {
      _analyzer: {
        rebuildGraph: vi.fn(() => ({ nodes: [], edges: [] } satisfies IGraphData)),
        registry: { notifyGraphRebuild: vi.fn() },
      },
      _disabledPlugins: new Set<string>(),
    };
    const rebuildAndSend = vi.fn();

    smartRebuildGraphView(state, 'plugin.alpha', {
      rebuildAndSend,
    });

    expect(rebuildAndSend).toHaveBeenCalledOnce();
  });

  it('returns early when a smart rebuild is requested without an analyzer', () => {
    const rebuildAndSend = vi.fn();

    smartRebuildGraphView(
      {
        _analyzer: undefined,
        _disabledPlugins: new Set<string>(),
      },
      'rule.alpha',
      {
        rebuildAndSend,
      },
    );

    expect(rebuildAndSend).not.toHaveBeenCalled();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IViewContext } from '../../../../../src/core/views/contracts';
import type { IGraphData } from '../../../../../src/shared/graph/types';
import { createGraphViewProviderViewSelectionMethods } from '../../../../../src/extension/graphView/provider/view/selection';

describe('graphView/provider/view/selection', () => {
  it('delegates focused-file updates through view selection helpers', () => {
    const source = createSource();
    const setFocusedFile = vi.fn((_state, nextFilePath, handlers) => {
      expect(nextFilePath).toBe('src/app.ts');
      handlers.applyViewTransform();
      handlers.sendMessage({ type: 'GRAPH_DATA_UPDATED', payload: { nodes: [], edges: [] } });
    });
    const dependencies = createDependencies({
      setFocusedFile,
    });
    const methods = createGraphViewProviderViewSelectionMethods(
      source as never,
      dependencies,
    );

    methods.setFocusedFile('src/app.ts');

    expect(setFocusedFile).toHaveBeenCalledOnce();
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'GRAPH_DATA_UPDATED',
      payload: { nodes: [], edges: [] },
    });
  });

  it('delegates depth-limit changes and reads back the current limit', async () => {
    const source = createSource();
    const setDepthLimit = vi.fn(async (_state, nextDepthLimit, handlers) => {
      expect(nextDepthLimit).toBe(7);
      await handlers.persistDepthLimit(nextDepthLimit);
      handlers.applyViewTransform();
      handlers.sendMessage({
        type: 'DEPTH_LIMIT_UPDATED',
        payload: { depthLimit: nextDepthLimit },
      });
    });
    const getDepthLimit = vi.fn(() => 7);
    const dependencies = createDependencies({
      setDepthLimit,
      getDepthLimit,
    });
    const methods = createGraphViewProviderViewSelectionMethods(
      source as never,
      dependencies,
    );

    await methods.setDepthLimit(7);

    expect(setDepthLimit).toHaveBeenCalledOnce();
    expect(dependencies.persistSetting).toHaveBeenCalledWith(
      'depthLimit',
      7,
    );
    expect(methods.getDepthLimit()).toBe(7);
    expect(getDepthLimit).toHaveBeenCalledWith(source._viewContext, 1);
  });

  it('toggles depth mode and tolerates missing transform broadcasters', async () => {
    const source = createSource({
      _applyViewTransform: undefined,
    });
    const dependencies = createDependencies();
    const methods = createGraphViewProviderViewSelectionMethods(
      source as never,
      dependencies,
    );

    await methods.setDepthMode(true);

    expect(dependencies.persistSetting).toHaveBeenCalledWith('depthMode', true);
    expect(source._depthMode).toBe(true);
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'DEPTH_MODE_UPDATED',
      payload: { depthMode: true },
    });
  });

  it('delegates focused-file and depth-limit handlers without view lookup helpers', async () => {
    const source = createSource({
      _applyViewTransform: undefined,
    });
    const setFocusedFile = vi.fn((_state, nextFilePath, handlers) => {
      expect(nextFilePath).toBeUndefined();
      handlers.applyViewTransform();
      handlers.sendMessage({ type: 'GRAPH_DATA_UPDATED', payload: { nodes: [], edges: [] } });
    });
    const setDepthLimit = vi.fn(async (_state, nextDepthLimit, handlers) => {
      expect(nextDepthLimit).toBe(4);
      handlers.applyViewTransform();
      await handlers.persistDepthLimit(nextDepthLimit);
      handlers.sendMessage({
        type: 'DEPTH_LIMIT_UPDATED',
        payload: { depthLimit: nextDepthLimit },
        });
    });
    const dependencies = createDependencies({
      setFocusedFile,
      setDepthLimit,
    });
    const methods = createGraphViewProviderViewSelectionMethods(
      source as never,
      dependencies,
    );

    methods.setFocusedFile(undefined);
    await methods.setDepthLimit(4);

    expect(dependencies.persistSetting).toHaveBeenCalledWith(
      'depthLimit',
      4,
    );
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'GRAPH_DATA_UPDATED',
      payload: { nodes: [], edges: [] },
    });
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'DEPTH_LIMIT_UPDATED',
      payload: { depthLimit: 4 },
    });
  });
});

function createSource(overrides: Partial<Record<string, unknown>> = {}) {
  return {
    _context: {
      workspaceState: {
        update: vi.fn(() => Promise.resolve()),
      },
    },
    _viewContext: {
      activePlugins: new Set<string>(),
      depthLimit: 1,
    } satisfies IViewContext,
    _depthMode: false,
    _applyViewTransform: vi.fn(),
    _sendMessage: vi.fn(),
    _graphData: { nodes: [], edges: [] } satisfies IGraphData,
    ...overrides,
  };
}

function createDependencies(
  overrides: Partial<Parameters<typeof createGraphViewProviderViewSelectionMethods>[1]> = {},
) {
  const configuration = {
    update: vi.fn(() => Promise.resolve()),
  };
  return {
    setFocusedFile: vi.fn(),
    setDepthLimit: vi.fn(async () => undefined),
    getDepthLimit: vi.fn((viewContext: IViewContext, defaultDepthLimit: number) =>
      viewContext.depthLimit ?? defaultDepthLimit,
    ),
    getConfiguration: vi.fn(() => configuration),
    persistSetting: vi.fn((_: string, __: unknown) => Promise.resolve()),
    defaultDepthLimit: 1,
    depthLimitKey: 'depthLimit',
    ...overrides,
  };
}

import { describe, expect, it, vi } from 'vitest';
import type { IGraphData } from '../../../../src/shared/graph/types';
import type { IViewContext } from '../../../../src/core/views/contracts';
import {
  getGraphViewDepthLimit,
  setGraphViewDepthLimit,
  setGraphViewFocusedFile,
} from '../../../../src/extension/graphView/view/selection';

describe('graphView/view/selection', () => {
  it('updates focused file and re-sends graph data only in depth mode', () => {
    const state = {
      _depthMode: true,
      _graphData: { nodes: [], edges: [] } satisfies IGraphData,
      _viewContext: {
        activePlugins: new Set(['plugin.alpha']),
        focusedFile: undefined,
      } satisfies IViewContext,
    };
    const applyViewTransform = vi.fn();
    const sendMessage = vi.fn();

    setGraphViewFocusedFile(state, 'src/app.ts', {
      applyViewTransform,
      sendMessage,
    });

    expect(state._viewContext.focusedFile).toBe('src/app.ts');
    expect(applyViewTransform).toHaveBeenCalledTimes(1);
    expect(sendMessage).toHaveBeenCalledWith({
      type: 'ACTIVE_FILE_UPDATED',
      payload: { filePath: 'src/app.ts' },
    });
    expect(sendMessage).toHaveBeenCalledWith({
      type: 'GRAPH_DATA_UPDATED',
      payload: { nodes: [], edges: [] },
    });
  });

  it('clamps depth limits, persists them, and re-sends graph data only in depth mode', async () => {
    const state = {
      _depthMode: true,
      _graphData: { nodes: [], edges: [] } satisfies IGraphData,
      _viewContext: { activePlugins: new Set(), depthLimit: 1 } satisfies IViewContext,
    };
    const persistDepthLimit = vi.fn(() => Promise.resolve());
    const sendMessage = vi.fn();
    const applyViewTransform = vi.fn();

    await setGraphViewDepthLimit(state, 99, {
      persistDepthLimit,
      sendMessage,
      applyViewTransform,
    });

    expect(state._viewContext.depthLimit).toBe(10);
    expect(persistDepthLimit).toHaveBeenCalledWith(10);
    expect(sendMessage).toHaveBeenNthCalledWith(1, {
      type: 'DEPTH_LIMIT_UPDATED',
      payload: { depthLimit: 10 },
    });
    expect(applyViewTransform).toHaveBeenCalledTimes(1);
    expect(sendMessage).toHaveBeenNthCalledWith(2, {
      type: 'GRAPH_DATA_UPDATED',
      payload: { nodes: [], edges: [] },
    });
  });

  it('returns the default depth limit when the view context does not set one', () => {
    expect(getGraphViewDepthLimit({ activePlugins: new Set() }, 1)).toBe(1);
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import type { IViewContext } from '../../../../../src/core/views/contracts';
import type { IGraphData } from '../../../../../src/shared/graph/types';

const mocks = vi.hoisted(() => ({
  setGraphViewFocusedFile: vi.fn(),
  setGraphViewDepthLimit: vi.fn(),
  getGraphViewDepthLimit: vi.fn(),
  updateCodeGraphyConfigurationSilently: vi.fn(() => Promise.resolve()),
}));

vi.mock('../../../../../src/extension/graphView/view/selection', () => ({
  setGraphViewFocusedFile: mocks.setGraphViewFocusedFile,
  setGraphViewDepthLimit: mocks.setGraphViewDepthLimit,
  getGraphViewDepthLimit: mocks.getGraphViewDepthLimit,
}));

vi.mock('../../../../../src/extension/repoSettings/current', () => ({
  updateCodeGraphyConfigurationSilently: mocks.updateCodeGraphyConfigurationSilently,
}));

import { createGraphViewProviderViewSelectionMethods } from '../../../../../src/extension/graphView/provider/view/selection';

describe('graphView/provider/view/selection default dependencies', () => {
  let configuration: {
    get: <T>(section: string, defaultValue: T) => T;
    update: ReturnType<typeof vi.fn>;
  };

  beforeEach(() => {
    mocks.setGraphViewFocusedFile.mockReset();
    mocks.setGraphViewDepthLimit.mockReset();
    mocks.getGraphViewDepthLimit.mockReset();
    mocks.updateCodeGraphyConfigurationSilently.mockReset();
    configuration = {
      get: ((_: string, defaultValue: unknown) => defaultValue) as <T>(
        section: string,
        defaultValue: T,
      ) => T,
      update: vi.fn(() => Promise.resolve()),
    };
    (vscode.workspace as unknown as { getConfiguration: ReturnType<typeof vi.fn> }).getConfiguration =
      vi.fn(() => configuration);
  });

  it('uses the default depth mode persistence delegates', async () => {
    const source = createSource();

    const methods = createGraphViewProviderViewSelectionMethods(source as never);
    await methods.setDepthMode(true);

    expect(mocks.updateCodeGraphyConfigurationSilently).toHaveBeenCalledWith('depthMode', true);
    expect(configuration.update).not.toHaveBeenCalled();
    expect(source._applyViewTransform).toHaveBeenCalledOnce();
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'DEPTH_MODE_UPDATED',
      payload: { depthMode: true },
    });
  });

  it('uses the default focused-file, depth-limit, and readback delegates', async () => {
    const source = createSource();

    mocks.setGraphViewFocusedFile.mockImplementation((_state, nextFilePath, handlers) => {
      expect(nextFilePath).toBe('src/index.ts');
      handlers.applyViewTransform();
      handlers.sendMessage({
        type: 'GRAPH_DATA_UPDATED',
        payload: { nodes: [], edges: [] },
      });
    });

    mocks.setGraphViewDepthLimit.mockImplementation(async (_state, nextDepthLimit, handlers) => {
      expect(nextDepthLimit).toBe(4);
      await handlers.persistDepthLimit(nextDepthLimit);
      handlers.applyViewTransform();
      handlers.sendMessage({
        type: 'DEPTH_LIMIT_UPDATED',
        payload: { depthLimit: nextDepthLimit },
      });
    });

    mocks.getGraphViewDepthLimit.mockImplementation(
      (viewContext: IViewContext, defaultDepthLimit: number) =>
        viewContext.depthLimit ?? defaultDepthLimit,
    );

    const methods = createGraphViewProviderViewSelectionMethods(source as never);
    methods.setFocusedFile('src/index.ts');
    await methods.setDepthLimit(4);

    expect(mocks.setGraphViewFocusedFile).toHaveBeenCalledOnce();
    expect(mocks.setGraphViewDepthLimit).toHaveBeenCalledOnce();
    expect(mocks.updateCodeGraphyConfigurationSilently).toHaveBeenCalledWith('depthLimit', 4);
    expect(configuration.update).not.toHaveBeenCalled();
    expect(source._applyViewTransform).toHaveBeenCalledTimes(2);
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'GRAPH_DATA_UPDATED',
      payload: { nodes: [], edges: [] },
    });
    expect(source._sendMessage).toHaveBeenCalledWith({
      type: 'DEPTH_LIMIT_UPDATED',
      payload: { depthLimit: 4 },
    });
    expect(methods.getDepthLimit()).toBe(1);
    expect(mocks.getGraphViewDepthLimit).toHaveBeenCalledWith(source._viewContext, 1);
  });
});

function createSource() {
  return {
    _context: {
      workspaceState: {
        update: vi.fn(() => Promise.resolve()),
      },
    },
    _viewContext: {
      activePlugins: new Set<string>(),
      depthLimit: 1,
    } satisfies IViewContext,
    _depthMode: false,
    _applyViewTransform: vi.fn(),
    _sendMessage: vi.fn(),
    _graphData: { nodes: [], edges: [] } satisfies IGraphData,
  };
}

import { describe, expect, it } from 'vitest';
import * as vscode from 'vscode';
import {
  buildGraphViewContext,
  getGraphViewActivePluginIds,
  getGraphViewRelativePath,
} from '../../../../src/extension/graphView/view/context';

describe('graphView/view/context', () => {
  it('returns an empty plugin id set when there is no analyzer', () => {
    expect([...getGraphViewActivePluginIds(undefined)]).toEqual([]);
  });

  it('collects active plugin ids from the analyzer registry', () => {
    const pluginIds = getGraphViewActivePluginIds({
      registry: {
        list: () => [
          { plugin: { id: 'plugin.alpha' } },
          { plugin: { id: 'plugin.beta' } },
          { plugin: { id: 'plugin.alpha' } },
          { plugin: {} },
        ],
      },
    });

    expect([...pluginIds]).toEqual(['plugin.alpha', 'plugin.beta']);
  });

  it('ignores plugin entries without an id', () => {
    const pluginIds = getGraphViewActivePluginIds({
      registry: {
        list: () => [{ plugin: {} }, {}],
      },
    });

    expect([...pluginIds]).toEqual([]);
  });

  it('returns workspace-relative paths through the shared path helper', () => {
    const relativePath = getGraphViewRelativePath(
      vscode.Uri.file('/workspace/src/app.ts'),
      [{ uri: vscode.Uri.file('/workspace') } as vscode.WorkspaceFolder],
      (uri: vscode.Uri) => uri.fsPath.replace('/workspace/', ''),
    );

    expect(relativePath).toBe('src/app.ts');
  });

  it('builds the current view context from workspace state and editor state', () => {
    const context = buildGraphViewContext({
      analyzer: {
        registry: {
          list: () => [{ plugin: { id: 'plugin.alpha' } }],
        },
      },
      workspaceFolders: [{ uri: vscode.Uri.file('/workspace') } as vscode.WorkspaceFolder],
      activeEditor: {
        document: { uri: vscode.Uri.file('/workspace/src/app.ts') },
      } as vscode.TextEditor,
      readSavedDepthLimit: () => 4,
      asRelativePath: (uri: vscode.Uri) => uri.fsPath.replace('/workspace/', ''),
      defaultDepthLimit: 1,
    });

    expect(context).toEqual({
      activePlugins: new Set(['plugin.alpha']),
      workspaceRoot: '/workspace',
      focusedFile: 'src/app.ts',
      depthLimit: 4,
    });
  });

  it('falls back to default context values without workspace or editor state', () => {
    const context = buildGraphViewContext({
      analyzer: undefined,
      workspaceFolders: undefined,
      activeEditor: undefined,
      readSavedDepthLimit: () => undefined,
      asRelativePath: () => 'ignored.ts',
      defaultDepthLimit: 3,
    });

    expect(context).toEqual({
      activePlugins: new Set(),
      workspaceRoot: undefined,
      focusedFile: undefined,
      depthLimit: 3,
    });
  });
});

